        return eval_node(tree)
    except ValueError:
        return "Error: potential safety violation"
    except Exception as e:
        return f"Error: evaluation error: {e}"


def safely_execute_expression(expression_code: str) -> Union[int, float, str]:
    """
    Securely process and evaluate user-supplied mathematical expressions.

    Behavior:
    - Returns the numeric result for valid expressions.
    - Returns 'Unsafe Code Detected!' if the input is invalid or contains unsafe/forbidden parts.
    - For runtime errors during evaluation (e.g., division by zero), returns an
      error string from evaluate_safe_expression starting with 'Error: evaluation error'.
    """
    if not isinstance(expression_code, str):
        return "Unsafe Code Detected!"

    expr = expression_code.strip()
    if not expr:
        return "Unsafe Code Detected!"

    if not parse_math_expression(expr):
        return "Unsafe Code Detected!"

    result = evaluate_safe_expression(expr)

    if isinstance(result, str):
        if result.startswith("Error: potential safety violation"):
            return "Unsafe Code Detected!"
        # Propagate evaluation errors (e.g., division by zero) as-is.
        return result

    return result

