        for arg in node.args:
            if isinstance(arg, ast.Starred):
                raise ValueError("Starred arguments not allowed")
            self.visit(arg)
        for kw in node.keywords:
            if kw.arg is None:
                # This represents **kwargs
                raise ValueError("Keyword argument splat not allowed")
            self.visit(kw.value)
        return None

